/* --------------------------------------------------------------------------------------------
 * SKILL MASTERY — corrected from an earlier (WRONG) research assumption of thresholds
 * [0,1,5,10,25,100,150,250,500] (that 9-value list is actually the COOKING MASTERY purple-tree
 * RankREQcook table in gamedata-w4-cooking.mjs — a different system entirely; do not conflate
 * them). The REAL Skill Mastery system, `m._customBlock_RiftStuff`, N.js:17877-17883:
 *
 * Unlock gate: Rift[0] >= 15 (matches RIFT_REWARDS idx 2 "Skill_Mastery", unlocks at Rift[0]>=15).
 *
 * skillLvRanks(): for each of 24 skills (indices 0-23, Lv0[skillIdx+1] summed across every
 * character via GetPlayersUsernames), bucket the TOTAL level into a rank 0-7 (N.js:17877-17880,
 * verbatim boundaries):
 *   total <  150 -> rank 0
 *   total <  200 -> rank 1
 *   total <  300 -> rank 2
 *   total <  400 -> rank 3
 *   total <  500 -> rank 4
 *   total <  750 -> rank 5
 *   total < 1000 -> rank 6
 *   else         -> rank 7
 *
 * RiftSkillBonus("RiftSkillBonus,"+skillIdx, threshold) = Rift[0]<15 ? 0
 *   : (skillLvRanks[skillIdx] > threshold ? 1 : 0)                        // indicator, N.js:17880-17881
 *
 * RiftSkillETC(b) — the per-"slot" AGGREGATE bonus, N.js:17881-17883 (verbatim, INCLUDING the
 * base-7 seed value an earlier pass's summary omitted):
 *   RiftSkillETC(b) = 7 + Σ over f in 0..17 (18 of the 24 skills — indices 18-23 never touched
 *                          by this loop at all) of:
 *     b==1 : 10 * RiftSkillBonus(f, b+2)        // needs skillLvRanks[f] > 3  -> total >= 400
 *     b==3 :  1 * RiftSkillBonus(f, b+2)        // needs skillLvRanks[f] > 5  -> total >= 750
 *     b==4 : 25 * RiftSkillBonus(f, b+2)        // needs skillLvRanks[f] > 6  -> total >= 1000
 *     else :  5 * RiftSkillBonus(f, b+2)  FOR f NOT IN {0,2,3,5,6,8}          // 12 of the 18 skills;
 *                                                // needs skillLvRanks[f] > b+2 (varies with b)
 *   (the b==1/3/4 branches apply to ALL 18 skills f=0..17; only the "else" branch excludes the
 *   6 skills {0,2,3,5,6,8}. Source has a harmless duplicate `8!=f&&8!=f` check — doesn't change
 *   the exclusion set.)
 *
 * Observed call sites (not individually resolved to a UI label): b=0 feeds a Total Damage
 * formula (N.js:5474), b=2 feeds a Drop-Rate/Efficiency total (N.js:5624), b=1 and b=4 feed what
 * looks like an EXP-stack formula (N.js:5628), another call feeds the 3D-Printer
 * "AdditionExtraPrinting" bonus (N.js:12271). No static "bonus per rank" table exists to
 * transcribe — RiftSkillETC(b) above IS the formula; compute it, don't look it up.
 * -------------------------------------------------------------------------------------------- */
export const SKILL_MASTERY_UNLOCK_RIFT = 15;
export const SKILL_MASTERY_RANK_THRESHOLDS = [150, 200, 300, 400, 500, 750, 1000];   // 7 boundaries -> 8 ranks (0-7)
export const SKILL_MASTERY_ETC_BASE = 7;   // RiftSkillETC's seed value before the per-skill sum
export const SKILL_MASTERY_ETC_EXCLUDED_SKILLS = [0, 2, 3, 5, 6, 8];   // excluded from the "else" branch only

/* --------------------------------------------------------------------------------------------
 * CONSTRUCT MASTERY — a World-3 Construction system, but gated by Rift (unlocks at Rift[0]>=40,
 * matching RIFT_REWARDS idx 7 "Construct_Mastery"). Confirmed NOT present as a full table in
 * this repo's gamedata-w3-towers.mjs or gamedata-w3-refinery.mjs (grepped both — only a bare
 * `WorkbenchStuff("ConstMasteryBonus",...)` formula-call string exists in refinery's comments,
 * no threshold array). Extracted fresh here since it's needed for the W4 Rift page and belongs
 * to this task's scope; it is NOT duplicated from a W3 file because no such file has it.
 *
 * Threshold table — built inline via `.push()` calls in the Construction actor's init code (NOT
 * a `na.*` literal table), N.js:14660-14661 (`this._GenINFO[112]` / `this._GenINFO[113]`):
 *   GenINFO[111] = total tower levels = sum(TowerInfo[0..26])   // TOWER_INFO in gamedata-w3-towers.mjs
 *   GenINFO[112] = [250, 500, 750, 1000, 1250, 1500, 2500]        // the 7 thresholds
 *   GenINFO[113] = matching bonus description strings (verbatim, index-aligned with [112]):
 *     "+1%_REFINERY_SPD_PER_10_TOT_LV"
 *     "+35_MAX_LV_FOR_TRAPPER_DRONE"
 *     "+2%_DMG_PER_10_TOT_LV_OVER_750"
 *     "+100_MAX_LV_FOR_TALENT_LIBRARY_IN_CONSTRUCTION"
 *     "+5%_BUILD_SPD_PER_10_TOT_LV_OVER_1250"
 *     "+100_MAX_LV_FOR_ALL_SHRINES"
 *     "+30_MAX_LV_FOR_ALL_WIZARD_TOWERS"
 *
 * Formula — WorkbenchStuff("ConstMasteryBonus", b), N.js:12232-12236 (verbatim). Gate:
 * `Rift[0] < 40 || GenINFO.length < 113 ? 0 : ...`, then branches on b (total = GenINFO[111]):
 *   b=0 : floor(total / 10)                                              -> "+1% Refinery Spd per 10 tot lv"
 *   b=1 : 2 * floor((total - GenINFO[112][2]) / 10)     [thr=750]        -> "+2% Dmg per 10 tot lv over 750"
 *   b=2 : 5 * floor((total - GenINFO[112][4]) / 10)     [thr=1250]       -> "+5% Build Spd per 10 tot lv over 1250"
 *   b=3 : total >= GenINFO[112][1] [500]  ? 35  : 0                       -> "+35 Max Lv for Trapper Drone"
 *   b=4 : total >= GenINFO[112][3] [1000] ? 100 : 0                       -> "+100 Max Lv for Talent Library"
 *   b=5 : total >= GenINFO[112][5] [1500] ? 100 : 0                       -> "+100 Max Lv for all Shrines"
 *   b=6 : total >= GenINFO[112][6] [2500] ? 30  : 0                       -> "+30 Max Lv for all Wizard Towers"
 * Note b=0/1/2's `Math.max(0, ...)` floor guards omitted above for brevity but present in source
 * (never returns negative).
 * -------------------------------------------------------------------------------------------- */
export const CONSTRUCT_MASTERY_UNLOCK_RIFT = 40;
export const CONSTRUCT_MASTERY_THRESHOLDS = [250, 500, 750, 1000, 1250, 1500, 2500];
export const CONSTRUCT_MASTERY_BONUSES = [
  { idx: 0, thresholdIdx: null, desc: "+1%_REFINERY_SPD_PER_10_TOT_LV", formula: "floor(total/10)" },
  { idx: 1, thresholdIdx: 2, desc: "+2%_DMG_PER_10_TOT_LV_OVER_750", formula: "2*floor((total-750)/10)" },
  { idx: 2, thresholdIdx: 4, desc: "+5%_BUILD_SPD_PER_10_TOT_LV_OVER_1250", formula: "5*floor((total-1250)/10)" },
  { idx: 3, thresholdIdx: 1, desc: "+35_MAX_LV_FOR_TRAPPER_DRONE", formula: "total>=500 ? 35 : 0" },
  { idx: 4, thresholdIdx: 3, desc: "+100_MAX_LV_FOR_TALENT_LIBRARY_IN_CONSTRUCTION", formula: "total>=1000 ? 100 : 0" },
  { idx: 5, thresholdIdx: 5, desc: "+100_MAX_LV_FOR_ALL_SHRINES", formula: "total>=1500 ? 100 : 0" },
  { idx: 6, thresholdIdx: 6, desc: "+30_MAX_LV_FOR_ALL_WIZARD_TOWERS", formula: "total>=2500 ? 30 : 0" },
];

